def build_users(conn):
    plans = {
        plan["_id"]: plan
        for plan in build_subscription_plans(conn)
    }

    devices = {
        device["_id"]: device
        for device in build_devices(conn)
    }

    user_device_rows = fetch_all(
        conn,
        """
        SELECT
            user_device_id,
            user_id,
            device_id,
            assigned_at,
            unassigned_at
        FROM user_devices
        """,
    )

    user_devices_by_user = {}

    for row in user_device_rows:
        user_id = row.get("user_id")
        device_id = row.get("device_id")
        device = devices.get(device_id)

        user_devices_by_user.setdefault(user_id, []).append({
            "userDeviceId": row.get("user_device_id"),
            "deviceId": device_id,
            "assignedAt": row.get("assigned_at"),
            "unassignedAt": row.get("unassigned_at"),
            "deviceSnapshot": {
                "macAddress": device.get("macAddress"),
                "model": device.get("model"),
                "deviceType": device.get("deviceType"),
            } if device else None,
        })

    users = fetch_all(
        conn,
        """
        SELECT
            user_id,
            plan_id,
            name,
            email,
            created_at
        FROM users
        """,
    )

    docs = []

    for user in users:
        plan = plans.get(user.get("plan_id"))

        docs.append({
            "_id": user.get("user_id"),
            "name": user.get("name"),
            "email": user.get("email"),
            "createdAt": user.get("created_at"),
            "planId": user.get("plan_id"),
            "planSnapshot": {
                "name": plan.get("name"),
                "retentionDays": plan.get("retentionDays"),
                "allowsAlerts": plan.get("allowsAlerts"),
                "price": plan.get("price"),
            } if plan else None,
            "devices": user_devices_by_user.get(user.get("user_id"), []),
        })

    return docs


def build_activities(conn):
    movies = fetch_one_map(
        conn,
        """
        SELECT
            movie_id,
            title,
            year
        FROM movie
        """,
        "movie_id",
    )

    genres = fetch_one_map(
        conn,
        """
        SELECT
            genre_id,
            name
        FROM genre
        """,
        "genre_id",
    )

    rows = fetch_all(
        conn,
        """
        SELECT
            os,
            app,
            device,
            cust_id,
            activity,
            genre_id,
            movie_id,
            activity_time
        FROM activity
        """,
    )

    docs = []

    for index, row in enumerate(rows, start=1):
        movie = movies.get(row.get("movie_id"))
        genre = genres.get(row.get("genre_id"))

        docs.append({
            "_id": f"activity_{index}",
            "customerId": row.get("cust_id"),
            "movieId": row.get("movie_id"),
            "genreId": row.get("genre_id"),
            "activity": row.get("activity"),
            "activityTime": row.get("activity_time"),
            "device": {
                "name": row.get("device"),
                "type": None,
            },
            "app": row.get("app"),
            "os": row.get("os"),
            "movieSnapshot": {
                "title": movie.get("title"),
                "year": movie.get("year"),
            } if movie else None,
            "genreSnapshot": {
                "genreId": genre.get("genre_id"),
                "name": genre.get("name"),
            } if genre else None,
        })

    return docs


