def replace_collection(db, collection_name, docs):
    collection = db[collection_name]
    collection.drop()

    if docs:
        collection.insert_many(docs, ordered=False)

    print(f"{collection_name}: {len(docs)} documentos migrados")


def create_indexes(db):
    db.movies.create_index([("title", ASCENDING)])
    db.movies.create_index([("genres.name", ASCENDING)])
    db.movies.create_index([("year", ASCENDING)])
    db.movies.create_index([("views", DESCENDING)])

    db.customers.create_index([("email", ASCENDING)])
    db.customers.create_index([("segment.segmentId", ASCENDING)])
    db.customers.create_index([("address.country", ASCENDING)])
    db.customers.create_index([("location", GEOSPHERE)])

    db.activities.create_index([("customerId", ASCENDING), ("activityTime", DESCENDING)])
    db.activities.create_index([("movieId", ASCENDING), ("activityTime", DESCENDING)])
    db.activities.create_index([("genreSnapshot.name", ASCENDING), ("activityTime", DESCENDING)])

    db.users.create_index([("email", ASCENDING)])
    db.users.create_index([("planId", ASCENDING)])
    db.users.create_index([("devices.deviceId", ASCENDING)])

    db.devices.create_index([("macAddress", ASCENDING)])

    db.subscription_plans.create_index([("name", ASCENDING)])

    db.user_sessions.create_index([("customerId", ASCENDING), ("startTime", DESCENDING)])

    print("�ndices creados")


